import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import {
  FiArrowRight,
  FiShield,
  FiGrid,
  FiClock,
  FiStar,
  FiUsers,
  FiCheckCircle,
  FiBookmark,
  FiSend,
  FiBriefcase,
  FiHelpCircle,
  FiSun,
  FiMoon,
  FiZap,
  FiLock,
  FiTrendingUp,
  FiMessageSquare,
  FiChevronDown,
  FiTwitter,
  FiGithub,
  FiLinkedin,
  FiCheck,
  FiGlobe,
} from 'react-icons/fi';
import { useTheme } from '../../context/ThemeContext';
import Logo from '../../components/common/Logo';

/* ─────────────────────────── DATA ─────────────────────────── */

const features = [
  {
    icon: FiCheckCircle,
    title: 'Verified Posts',
    desc: 'Every project post undergoes mandatory admin review before going live, keeping spam and fake listings away.',
    color: 'var(--green)',
    gradient: 'linear-gradient(135deg, #10b98120, #10b98105)',
  },
  {
    icon: FiGrid,
    title: 'Instagram-Style Feed',
    desc: 'Infinite-scroll feed with real-time filters, instant likes, and interactive inline comment sections.',
    color: 'var(--neon)',
    gradient: 'linear-gradient(135deg, #3b82f620, #3b82f605)',
  },
  {
    icon: FiSend,
    title: 'Real-Time Chat',
    desc: 'Message other freelancers and clients instantly with our integrated direct messaging desk.',
    color: 'var(--neon-light)',
    gradient: 'linear-gradient(135deg, #60a5fa20, #60a5fa05)',
  },
  {
    icon: FiBriefcase,
    title: 'Smart Proposals',
    desc: 'Apply directly to project listings, outline your rates and timeline, and track bid statuses live.',
    color: 'var(--purple)',
    gradient: 'linear-gradient(135deg, #8b5cf620, #8b5cf605)',
  },
  {
    icon: FiBookmark,
    title: 'Saved Bookmarks',
    desc: 'Bookmark listings and portfolios to your private board for quick retrieval anytime, anywhere.',
    color: 'var(--amber)',
    gradient: 'linear-gradient(135deg, #f59e0b20, #f59e0b05)',
  },
  {
    icon: FiHelpCircle,
    title: 'Support Desk',
    desc: 'Submit ticket inquiries directly to system admins and communicate until fully resolved.',
    color: 'var(--purple)',
    gradient: 'linear-gradient(135deg, #8b5cf620, #8b5cf605)',
  },
  {
    icon: FiShield,
    title: 'Admin Moderation',
    desc: 'Powerful admin console for managing users, approving posts, blocking accounts, and exporting CSV logs.',
    color: 'var(--red)',
    gradient: 'linear-gradient(135deg, #ef444420, #ef444405)',
  },
  {
    icon: FiUsers,
    title: 'Rich Profiles',
    desc: 'Showcase skills, bio, portfolio images, and broadcast your active or offline status to clients.',
    color: 'var(--green)',
    gradient: 'linear-gradient(135deg, #10b98120, #10b98105)',
  },
  {
    icon: FiLock,
    title: 'Secure Sessions',
    desc: 'Strict 5-hour auto-expiring sessions combined with complete device and IP-level activity logging.',
    color: 'var(--amber)',
    gradient: 'linear-gradient(135deg, #f59e0b20, #f59e0b05)',
  },
];

const testimonials = [
  {
    name: 'Priya Sharma',
    role: 'UI/UX Designer',
    avatar: 'PS',
    avatarColor: 'linear-gradient(135deg, #3b82f6, #8b5cf6)',
    quote: 'FreelanceHub completely changed how I find clients. The verified feed means I only see real, quality projects — no spam, no noise.',
    rating: 5,
  },
  {
    name: 'Arjun Mehta',
    role: 'Full Stack Developer',
    avatar: 'AM',
    avatarColor: 'linear-gradient(135deg, #10b981, #3b82f6)',
    quote: 'The built-in messaging and proposal tracking saved me hours every week. Everything I need in one polished platform.',
    rating: 5,
  },
  {
    name: 'Riya Nair',
    role: 'Content Strategist',
    avatar: 'RN',
    avatarColor: 'linear-gradient(135deg, #f59e0b, #ef4444)',
    quote: "I landed three long-term clients in my first month. The moderation quality is unlike any other platform I've used.",
    rating: 5,
  },
  {
    name: 'Karan Joshi',
    role: 'Startup Founder',
    avatar: 'KJ',
    avatarColor: 'linear-gradient(135deg, #8b5cf6, #ec4899)',
    quote: 'Finding vetted freelancers used to take weeks. On FreelanceHub I posted a project and had 12 proposals within hours.',
    rating: 5,
  },
];

const faqs = [
  {
    q: 'Is FreelanceHub free to join?',
    a: 'Yes, registration is completely free and instant. You can create your profile, browse the feed, and start applying to projects right away with no upfront cost.',
  },
  {
    q: 'How does post moderation work?',
    a: 'Every post goes into a pending queue after submission. Our admin team reviews each post for quality and authenticity before it appears in the live feed. This keeps the platform spam-free.',
  },
  {
    q: 'Can I message clients directly?',
    a: 'Absolutely. Once a proposal is accepted, a private direct-message channel is automatically unlocked between the freelancer and the client, with auto-refreshing conversations.',
  },
  {
    q: 'How secure is my account?',
    a: 'We use bcrypt password hashing, HTTP-only secure cookies, and sessions expire automatically after 5 hours. All activity is logged by device and IP for your safety.',
  },
  {
    q: 'What if I forget my password?',
    a: 'Use the "Forgot Password?" link on the login page. A secure reset link will be generated (valid for 15 minutes) that lets you set a new password instantly.',
  },
  {
    q: 'Can I showcase a portfolio?',
    a: 'Yes! Your profile page supports uploading images, listing skill tags, writing a bio, and setting your active/offline availability status for clients to see.',
  },
];

const workflow = [
  {
    step: '01',
    icon: FiZap,
    title: 'Sign Up & Build Profile',
    desc: 'Register for free in seconds. Add your skills, portfolio images, and bio to stand out to potential clients.',
    color: 'var(--neon)',
  },
  {
    step: '02',
    icon: FiGrid,
    title: 'Browse & Post Projects',
    desc: 'Post your services or browse verified project listings filtered by skill, budget, or category.',
    color: 'var(--green)',
  },
  {
    step: '03',
    icon: FiBriefcase,
    title: 'Send Smart Proposals',
    desc: 'Apply to projects with cover letters and bid rates. Track your proposal status in real time.',
    color: 'var(--purple)',
  },
  {
    step: '04',
    icon: FiMessageSquare,
    title: 'Collaborate & Deliver',
    desc: 'Chat directly once accepted. Communicate, share files, and deliver exceptional work.',
    color: 'var(--amber)',
  },
];

/* ─────────────────────────── ANIMATIONS ─────────────────────────── */

const fadeUp = {
  hidden: { opacity: 0, y: 28 },
  visible: (i = 0) => ({
    opacity: 1,
    y: 0,
    transition: { type: 'spring', stiffness: 90, damping: 18, delay: i * 0.07 },
  }),
};

const stagger = {
  hidden: { opacity: 0 },
  visible: { opacity: 1, transition: { staggerChildren: 0.08 } },
};

/* ─────────────────────────── SUB-COMPONENTS ─────────────────────────── */

function SectionLabel({ children }) {
  return (
    <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full text-[10px] sm:text-xs font-bold uppercase tracking-widest mb-3"
      style={{ background: 'rgba(59,130,246,0.1)', color: 'var(--neon-light)', border: '1px solid rgba(59,130,246,0.2)' }}>
      {children}
    </div>
  );
}

function StarRating({ count = 5 }) {
  return (
    <div className="flex gap-0.5 mb-3">
      {Array.from({ length: count }).map((_, i) => (
        <FiStar key={i} size={13} fill="var(--amber)" style={{ color: 'var(--amber)' }} />
      ))}
    </div>
  );
}

function FAQItem({ q, a }) {
  const [open, setOpen] = useState(false);
  return (
    <div
      className="border rounded-xl overflow-hidden transition-all duration-300 cursor-pointer"
      style={{
        borderColor: open ? 'rgba(59,130,246,0.35)' : 'var(--border)',
        background: open ? 'rgba(59,130,246,0.04)' : 'var(--bg-surface)',
      }}
      onClick={() => setOpen(!open)}
    >
      <div className="flex items-center justify-between gap-3 p-4 md:p-5">
        <span className="font-semibold text-sm md:text-base" style={{ color: 'var(--text-primary)' }}>{q}</span>
        <motion.div animate={{ rotate: open ? 180 : 0 }} transition={{ duration: 0.25 }} className="flex-shrink-0">
          <FiChevronDown size={18} style={{ color: 'var(--text-muted)' }} />
        </motion.div>
      </div>
      <AnimatePresence initial={false}>
        {open && (
          <motion.div
            key="answer"
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.28, ease: 'easeInOut' }}
          >
            <p className="px-4 md:px-5 pb-4 md:pb-5 text-sm leading-relaxed" style={{ color: 'var(--text-secondary)' }}>{a}</p>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

/* ─────────────────────────── MAIN PAGE ─────────────────────────── */

export default function Landing() {
  const { isDark, toggleTheme } = useTheme();
  const [activeTestimonial, setActiveTestimonial] = useState(0);

  // Auto-rotate testimonials
  useEffect(() => {
    const t = setInterval(() => setActiveTestimonial(p => (p + 1) % testimonials.length), 5000);
    return () => clearInterval(t);
  }, []);

  return (
    <div style={{ background: 'var(--bg-primary)', minHeight: '100vh', position: 'relative', overflow: 'hidden' }}>

      {/* ── Ambient Background Orbs ── */}
      <div className="pointer-events-none fixed inset-0 overflow-hidden" style={{ zIndex: 0 }}>
        <div style={{
          position: 'absolute', top: '-15%', left: '-5%',
          width: '55vw', height: '55vw', borderRadius: '50%',
          background: 'radial-gradient(circle, rgba(59,130,246,0.12) 0%, transparent 65%)',
          filter: 'blur(80px)',
        }} />
        <div style={{
          position: 'absolute', top: '35%', right: '-10%',
          width: '45vw', height: '45vw', borderRadius: '50%',
          background: 'radial-gradient(circle, rgba(139,92,246,0.1) 0%, transparent 65%)',
          filter: 'blur(80px)',
        }} />
        <div style={{
          position: 'absolute', bottom: '-5%', left: '20%',
          width: '40vw', height: '40vw', borderRadius: '50%',
          background: 'radial-gradient(circle, rgba(16,185,129,0.07) 0%, transparent 65%)',
          filter: 'blur(80px)',
        }} />
      </div>

      {/* ── Navigation ── */}
      <nav className="sticky top-0 z-50 flex items-center gap-2 md:gap-3 px-4 md:px-10 py-3 md:py-4"
        style={{
          background: 'var(--header-bg)',
          borderBottom: '1px solid var(--border)',
          backdropFilter: 'blur(20px)',
          WebkitBackdropFilter: 'blur(20px)',
        }}>
        <Logo size={32} rounded={8} className="flex-shrink-0" />
        <span className="font-display font-extrabold text-sm sm:text-base flex-1 truncate"
          style={{ color: 'var(--text-primary)', letterSpacing: '-0.5px' }}>
          FreelanceHub
        </span>
        <button onClick={toggleTheme} className="btn-ghost p-1.5 md:p-2 rounded-lg flex-shrink-0" aria-label="Toggle Theme">
          {isDark ? <FiSun size={15} /> : <FiMoon size={15} />}
        </button>
        <Link to="/login" className="btn-ghost text-xs md:text-sm px-2.5 py-1.5 md:px-4 md:py-2 flex-shrink-0">Sign In</Link>
        <Link to="/register" className="btn-neon text-xs md:text-sm px-3 py-1.5 md:px-5 md:py-2 flex-shrink-0">
          Get Started <FiArrowRight size={13} />
        </Link>
      </nav>

      {/* ── HERO ── */}
      <section className="relative z-10 text-center px-4 sm:px-6 pt-16 md:pt-24 pb-12 md:pb-20 max-w-5xl mx-auto">
        <motion.div variants={stagger} initial="hidden" animate="visible" className="flex flex-col items-center">

          {/* Badge */}
          <motion.div variants={fadeUp}
            className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] sm:text-xs font-semibold mb-6 border"
            style={{
              background: 'var(--bg-surface-2)',
              borderColor: 'var(--border-neon)',
              color: 'var(--neon-light)',
              boxShadow: 'var(--shadow-neon)',
            }}>
            <span className="flex h-2 w-2 relative">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75" />
              <span className="relative inline-flex rounded-full h-2 w-2 bg-blue-500" />
            </span>
            ✦ India's premium freelancer platform
          </motion.div>

          {/* Headline */}
          <motion.h1 variants={fadeUp}
            className="font-display font-extrabold text-4xl sm:text-5xl md:text-7xl leading-[1.05] mb-5 md:mb-7"
            style={{ color: 'var(--text-primary)', letterSpacing: '-2px' }}>
            Where Top Freelancers<br />
            <span className="gradient-text">Connect & Thrive</span>
          </motion.h1>

          {/* Subheadline */}
          <motion.p variants={fadeUp}
            className="text-sm sm:text-base md:text-lg leading-relaxed mb-8 md:mb-10 max-w-2xl mx-auto"
            style={{ color: 'var(--text-secondary)' }}>
            Showcase your portfolio, apply to verified jobs, message clients in real-time, and bookmark
            your favourite posts — all within one beautifully moderated platform.
          </motion.p>

          {/* CTAs */}
          <motion.div variants={fadeUp} className="flex items-center justify-center gap-3 flex-wrap mb-14 md:mb-20">
            <Link to="/register"
              className="btn-neon text-sm md:text-base px-7 md:px-9 py-2.5 md:py-3.5 rounded-xl shadow-lg hover:shadow-blue-500/25 font-semibold">
              Start for Free <FiArrowRight size={16} />
            </Link>
            <Link to="/login"
              className="btn-ghost text-sm md:text-base px-7 md:px-9 py-2.5 md:py-3.5 rounded-xl">
              Sign In →
            </Link>
          </motion.div>

          {/* Stats Grid */}
          <motion.div variants={fadeUp} className="grid grid-cols-2 md:grid-cols-4 gap-3 md:gap-4 w-full max-w-3xl">
            {[
              { val: '500+', label: 'Active Freelancers', icon: FiUsers, color: 'var(--neon)' },
              { val: '1,200+', label: 'Projects Posted', icon: FiBriefcase, color: 'var(--green)' },
              { val: '98%', label: 'Approval Rate', icon: FiShield, color: 'var(--amber)' },
              { val: '< 1 day', label: 'Avg. Review Time', icon: FiClock, color: 'var(--purple)' },
            ].map((stat) => (
              <motion.div
                key={stat.label}
                whileHover={{ y: -4, borderColor: 'var(--border-neon)', boxShadow: 'var(--shadow-neon)' }}
                className="surface-card p-4 text-center border transition-all duration-300"
                style={{ borderTop: `2px solid ${stat.color}`, borderColor: 'var(--border)' }}>
                <stat.icon size={18} className="mx-auto mb-1.5" style={{ color: stat.color }} />
                <div className="font-display font-extrabold text-xl sm:text-2xl gradient-text">{stat.val}</div>
                <div className="text-[10px] sm:text-[11px] mt-0.5 font-medium" style={{ color: 'var(--text-muted)' }}>{stat.label}</div>
              </motion.div>
            ))}
          </motion.div>
        </motion.div>
      </section>

      {/* ── TRUST BAR ── */}
      <section className="relative z-10 border-y py-5 md:py-6 overflow-hidden"
        style={{ borderColor: 'var(--border)', background: 'var(--bg-surface)' }}>
        <div className="flex items-center justify-center gap-3 px-4 flex-wrap">
          <span className="text-[10px] sm:text-xs font-semibold uppercase tracking-widest mr-3" style={{ color: 'var(--text-muted)' }}>
            Trusted by professionals across
          </span>
          {['Design', 'Development', 'Content', 'Marketing', 'Finance', 'Photography'].map((skill) => (
            <span key={skill}
              className="inline-flex items-center gap-1.5 text-[11px] sm:text-xs font-medium px-3 py-1 rounded-full"
              style={{ background: 'var(--bg-surface-2)', color: 'var(--text-secondary)', border: '1px solid var(--border)' }}>
              <FiCheck size={10} style={{ color: 'var(--green)' }} /> {skill}
            </span>
          ))}
        </div>
      </section>

      {/* ── FEATURES ── */}
      <section className="relative z-10 px-4 sm:px-8 py-16 md:py-24 max-w-7xl mx-auto">
        <div className="text-center max-w-2xl mx-auto mb-12 md:mb-16">
          <SectionLabel><FiZap size={10} /> Platform Capabilities</SectionLabel>
          <h2 className="font-display font-bold text-2xl sm:text-4xl md:text-5xl mb-4"
            style={{ color: 'var(--text-primary)', letterSpacing: '-1px' }}>
            Everything You Need to Scale
          </h2>
          <p className="text-sm sm:text-base" style={{ color: 'var(--text-secondary)' }}>
            Advanced features built specifically to make freelancing and hiring seamless, safe, and efficient.
          </p>
        </div>

        <motion.div
          variants={stagger}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, margin: '-80px' }}
          className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-5"
        >
          {features.map((f, i) => (
            <motion.div
              key={f.title}
              custom={i}
              variants={fadeUp}
              whileHover={{ y: -6, borderColor: 'var(--border-neon)', boxShadow: 'var(--shadow-neon)' }}
              className="relative p-5 md:p-6 rounded-2xl border overflow-hidden group transition-all duration-300 cursor-default"
              style={{ background: f.gradient, borderColor: 'var(--border)' }}
            >
              {/* Subtle top glow bar */}
              <div className="absolute top-0 left-0 right-0 h-[1px] opacity-0 group-hover:opacity-100 transition-opacity duration-300"
                style={{ background: `linear-gradient(90deg, transparent, ${f.color}, transparent)` }} />

              <div className="w-11 h-11 rounded-xl flex items-center justify-center mb-4 transition-transform duration-300 group-hover:scale-110"
                style={{ background: `${f.color}18`, color: f.color, border: `1px solid ${f.color}28` }}>
                <f.icon size={20} />
              </div>
              <h3 className="font-display font-bold text-sm md:text-base mb-2" style={{ color: 'var(--text-primary)' }}>{f.title}</h3>
              <p className="text-xs md:text-sm leading-relaxed" style={{ color: 'var(--text-secondary)' }}>{f.desc}</p>
            </motion.div>
          ))}
        </motion.div>
      </section>

      {/* ── HOW IT WORKS ── */}
      <section className="relative z-10 px-4 sm:px-8 py-16 md:py-24"
        style={{ background: 'var(--bg-surface)', borderTop: '1px solid var(--border)', borderBottom: '1px solid var(--border)' }}>
        <div className="max-w-6xl mx-auto">
          <div className="text-center max-w-2xl mx-auto mb-12 md:mb-16">
            <SectionLabel><FiTrendingUp size={10} /> How It Works</SectionLabel>
            <h2 className="font-display font-bold text-2xl sm:text-4xl md:text-5xl mb-4"
              style={{ color: 'var(--text-primary)', letterSpacing: '-1px' }}>
              From Sign-Up to Success
            </h2>
            <p className="text-sm sm:text-base" style={{ color: 'var(--text-secondary)' }}>
              A seamless, moderated journey from first login to thriving collaboration.
            </p>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5 md:gap-6">
            {workflow.map((flow, idx) => (
              <motion.div
                key={flow.step}
                initial={{ opacity: 0, y: 30 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true, margin: '-40px' }}
                transition={{ delay: idx * 0.1, type: 'spring', stiffness: 80 }}
                whileHover={{ y: -5 }}
                className="relative p-6 rounded-2xl border group transition-all duration-300"
                style={{ background: 'var(--bg-secondary)', borderColor: 'var(--border)' }}
              >
                {/* Connector line (desktop) */}
                {idx < workflow.length - 1 && (
                  <div className="hidden lg:block absolute top-12 left-full w-6 h-[1px] z-10"
                    style={{ background: 'var(--border)' }} />
                )}

                <div className="w-12 h-12 rounded-xl flex items-center justify-center mb-5 transition-transform duration-300 group-hover:scale-110"
                  style={{ background: `${flow.color}15`, color: flow.color, border: `1px solid ${flow.color}25` }}>
                  <flow.icon size={22} />
                </div>

                <div className="font-display font-extrabold text-3xl md:text-4xl mb-3 opacity-[0.08] group-hover:opacity-20 transition-opacity select-none"
                  style={{ color: flow.color }}>
                  {flow.step}
                </div>

                <h3 className="font-display font-bold text-sm md:text-base mb-2" style={{ color: 'var(--text-primary)' }}>
                  {flow.title}
                </h3>
                <p className="text-xs md:text-sm leading-relaxed" style={{ color: 'var(--text-secondary)' }}>
                  {flow.desc}
                </p>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* ── TESTIMONIALS ── */}
      <section className="relative z-10 px-4 sm:px-8 py-16 md:py-24 max-w-6xl mx-auto">
        <div className="text-center max-w-2xl mx-auto mb-12 md:mb-16">
          <SectionLabel><FiStar size={10} /> Testimonials</SectionLabel>
          <h2 className="font-display font-bold text-2xl sm:text-4xl md:text-5xl mb-4"
            style={{ color: 'var(--text-primary)', letterSpacing: '-1px' }}>
            Loved by Freelancers
          </h2>
          <p className="text-sm sm:text-base" style={{ color: 'var(--text-secondary)' }}>
            Real stories from real professionals who found success on FreelanceHub.
          </p>
        </div>

        {/* Testimonial Cards Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 md:gap-5">
          {testimonials.map((t, i) => (
            <motion.div
              key={t.name}
              initial={{ opacity: 0, y: 24 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: i * 0.1, type: 'spring', stiffness: 80 }}
              whileHover={{ y: -4, borderColor: 'var(--border-neon)' }}
              className="p-5 md:p-7 rounded-2xl border transition-all duration-300"
              style={{ background: 'var(--bg-surface)', borderColor: 'var(--border)' }}
            >
              <StarRating count={t.rating} />
              <p className="text-sm md:text-base leading-relaxed mb-5"
                style={{ color: 'var(--text-secondary)', fontStyle: 'italic' }}>
                "{t.quote}"
              </p>
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-full flex items-center justify-center text-white text-xs font-bold flex-shrink-0"
                  style={{ background: t.avatarColor }}>
                  {t.avatar}
                </div>
                <div>
                  <div className="font-semibold text-sm" style={{ color: 'var(--text-primary)' }}>{t.name}</div>
                  <div className="text-xs" style={{ color: 'var(--text-muted)' }}>{t.role}</div>
                </div>
              </div>
            </motion.div>
          ))}
        </div>

        {/* Dot indicator */}
        <div className="flex justify-center gap-2 mt-8">
          {testimonials.map((_, i) => (
            <button
              key={i}
              onClick={() => setActiveTestimonial(i)}
              className="rounded-full transition-all duration-300"
              style={{
                width: i === activeTestimonial ? 24 : 8,
                height: 8,
                background: i === activeTestimonial ? 'var(--neon)' : 'var(--border)',
              }}
            />
          ))}
        </div>
      </section>

      {/* ── FAQ ── */}
      <section className="relative z-10 px-4 sm:px-8 py-16 md:py-24"
        style={{ background: 'var(--bg-surface)', borderTop: '1px solid var(--border)', borderBottom: '1px solid var(--border)' }}>
        <div className="max-w-3xl mx-auto">
          <div className="text-center mb-12 md:mb-16">
            <SectionLabel><FiHelpCircle size={10} /> FAQ</SectionLabel>
            <h2 className="font-display font-bold text-2xl sm:text-4xl md:text-5xl mb-4"
              style={{ color: 'var(--text-primary)', letterSpacing: '-1px' }}>
              Common Questions
            </h2>
            <p className="text-sm sm:text-base" style={{ color: 'var(--text-secondary)' }}>
              Everything you need to know before getting started.
            </p>
          </div>

          <div className="space-y-3">
            {faqs.map((faq) => (
              <FAQItem key={faq.q} q={faq.q} a={faq.a} />
            ))}
          </div>
        </div>
      </section>

      {/* ── CTA BANNER ── */}
      <section className="relative z-10 px-4 sm:px-8 py-16 md:py-24 max-w-5xl mx-auto">
        <motion.div
          initial={{ opacity: 0, scale: 0.97 }}
          whileInView={{ opacity: 1, scale: 1 }}
          viewport={{ once: true }}
          transition={{ type: 'spring', stiffness: 80 }}
          className="relative rounded-3xl p-8 md:p-16 text-center overflow-hidden border"
          style={{
            background: 'linear-gradient(135deg, rgba(59,130,246,0.12), rgba(139,92,246,0.1), rgba(16,185,129,0.08))',
            borderColor: 'rgba(59,130,246,0.3)',
          }}
        >
          {/* Glow blobs inside banner */}
          <div className="absolute -right-16 -top-16 w-64 h-64 rounded-full pointer-events-none"
            style={{ background: 'radial-gradient(circle, rgba(59,130,246,0.2) 0%, transparent 70%)', filter: 'blur(40px)' }} />
          <div className="absolute -left-16 -bottom-16 w-64 h-64 rounded-full pointer-events-none"
            style={{ background: 'radial-gradient(circle, rgba(139,92,246,0.15) 0%, transparent 70%)', filter: 'blur(40px)' }} />

          <div className="relative">
            <div className="inline-flex items-center gap-2 text-xs font-semibold mb-5 px-3 py-1 rounded-full"
              style={{ background: 'rgba(16,185,129,0.12)', color: 'var(--green)', border: '1px solid rgba(16,185,129,0.25)' }}>
              <FiCheck size={11} /> Free to join · No credit card required
            </div>

            <h2 className="font-display font-bold text-2xl sm:text-4xl md:text-5xl mb-4"
              style={{ color: 'var(--text-primary)', letterSpacing: '-1px' }}>
              Ready to Level Up<br />Your Freelance Game?
            </h2>
            <p className="text-sm sm:text-base max-w-lg mx-auto mb-8"
              style={{ color: 'var(--text-secondary)', lineHeight: '1.7' }}>
              Join 500+ verified freelancers already building their reputation, landing better clients,
              and collaborating effortlessly — all on one beautifully designed platform.
            </p>
            <div className="flex items-center justify-center gap-3 flex-wrap">
              <Link to="/register"
                className="btn-neon text-sm md:text-base px-8 md:px-10 py-3 md:py-3.5 rounded-xl shadow-lg font-semibold">
                Create Free Account <FiArrowRight size={16} />
              </Link>
              <Link to="/login"
                className="btn-ghost text-sm md:text-base px-6 md:px-8 py-3 md:py-3.5 rounded-xl">
                Sign In
              </Link>
            </div>
          </div>
        </motion.div>
      </section>

      {/* ── FOOTER ── */}
      <footer className="relative z-10 border-t" style={{ borderColor: 'var(--border)', background: 'var(--bg-surface)' }}>
        <div className="max-w-6xl mx-auto px-4 sm:px-8 py-10 md:py-14">
          <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-8 md:gap-10 mb-10">

            {/* Brand */}
            <div className="md:col-span-2">
              <div className="flex items-center gap-2.5 mb-3">
                <Logo size={32} rounded={8} />
                <span className="font-display font-extrabold text-base" style={{ color: 'var(--text-primary)' }}>FreelanceHub</span>
              </div>
              <p className="text-xs sm:text-sm leading-relaxed mb-4 max-w-xs" style={{ color: 'var(--text-muted)' }}>
                India's premium moderated platform for freelancers and clients to connect, collaborate, and build meaningful work relationships.
              </p>
              <div className="flex items-center gap-2">
                {[FiTwitter, FiGithub, FiLinkedin, FiGlobe].map((Icon, i) => (
                  <a key={i} href="#" className="w-8 h-8 flex items-center justify-center rounded-lg transition-colors"
                    style={{ color: 'var(--text-muted)', background: 'var(--bg-surface-2)', border: '1px solid var(--border)' }}
                    onMouseEnter={e => e.currentTarget.style.color = 'var(--neon-light)'}
                    onMouseLeave={e => e.currentTarget.style.color = 'var(--text-muted)'}>
                    <Icon size={14} />
                  </a>
                ))}
              </div>
            </div>

            {/* Platform links */}
            <div>
              <div className="font-semibold text-xs uppercase tracking-widest mb-4" style={{ color: 'var(--text-muted)' }}>Platform</div>
              <ul className="space-y-2.5">
                {[
                  { label: 'Browse Feed', to: '/login' },
                  { label: 'Sign In', to: '/login' },
                  { label: 'Register', to: '/register' },
                  { label: 'Forgot Password', to: '/forgot-password' },
                ].map(link => (
                  <li key={link.label}>
                    <Link to={link.to} className="text-xs sm:text-sm transition-colors"
                      style={{ color: 'var(--text-secondary)' }}
                      onMouseEnter={e => e.currentTarget.style.color = 'var(--neon-light)'}
                      onMouseLeave={e => e.currentTarget.style.color = 'var(--text-secondary)'}>
                      {link.label}
                    </Link>
                  </li>
                ))}
              </ul>
            </div>

            {/* Features links */}
            <div>
              <div className="font-semibold text-xs uppercase tracking-widest mb-4" style={{ color: 'var(--text-muted)' }}>Features</div>
              <ul className="space-y-2.5">
                {['Verified Posts', 'Smart Proposals', 'Real-Time Chat', 'Bookmarks', 'Support Desk'].map(feat => (
                  <li key={feat}>
                    <span className="text-xs sm:text-sm" style={{ color: 'var(--text-secondary)' }}>{feat}</span>
                  </li>
                ))}
              </ul>
            </div>
          </div>

          {/* Bottom bar */}
          <div className="flex flex-col sm:flex-row items-center justify-between gap-3 pt-8 border-t"
            style={{ borderColor: 'var(--border)' }}>
            <p className="text-[10px] sm:text-xs" style={{ color: 'var(--text-muted)' }}>
              © 2026 FreelanceHub · All rights reserved.
            </p>
            <p className="text-[10px] sm:text-xs" style={{ color: 'var(--text-muted)' }}>
              Designed &amp; Developed by{' '}
              <a href="https://cloudhawk.in" target="_blank" rel="noreferrer"
                className="transition-colors"
                style={{ color: 'var(--neon-light)' }}
                onMouseEnter={e => e.currentTarget.style.textDecoration = 'underline'}
                onMouseLeave={e => e.currentTarget.style.textDecoration = 'none'}>
                CloudHawk
              </a>
            </p>
          </div>
        </div>
      </footer>
    </div>
  );
}
